<div class="card print-card"><div class="card-head between"><h3>Transaction Detail</h3><button onclick="window.print()" class="btn btn-outline">Print</button></div><div class="detail-grid"><div><strong>Reference:</strong> <?= e($transaction['reference_no']) ?></div><div><strong>Type:</strong> <?= e(ucwords(str_replace('_', ' ', $transaction['type']))) ?></div><div><strong>Direction:</strong> <?= e($transaction['direction']) ?></div><div><strong>Status:</strong> <?= e($transaction['status']) ?></div><div><strong>Amount:</strong> <?= money((float)$transaction['amount']) ?></div><div><strong>Related User:</strong> <?= e($transaction['related_name'] ?? '-') ?></div><div><strong>Description:</strong> <?= e($transaction['description'] ?? '-') ?></div><div><strong>Date:</strong> <?= e($transaction['created_at']) ?></div></div></div>
